methods.content:
/**
 * Returns the locale info.
 * @returns The locale info.
 */
getLocaleInfo(): { code: string; language: string; region: string; timezone: string; }

/**
 * Returns the calendar.
 * @returns The calendar.
 */
getCalendar(): { system: string; week: { startsOn: number; weekends: number[] }; clock: { format24Hour: boolean } }

/**
 * Returns the formats.
 * @returns The formats.
 */
getFormats(): { date: FormatPattern; time: FormatPattern; datetime: FormatPattern; numbers: { decimalPattern: string; currency: { code: string } }; contacts: { phone: string; postalCode: string } }

/**
 * Returns the units.
 * @returns The units.
 */
getUnits(): { temperature: string; distance: string; weight: string; volume: string; speed: string; area: string; custom?: Record<string, string> }

/**
 * Returns the i18n meta.
 * @returns The i18n meta.
 */
i18nMeta(): { fallbackLocales?: string[]; supportedLanguages?: string[]; rtl: boolean }
